// Funkcja do tłumaczenia strony
function translatePage(lang) {
    // Zapisz wybrany język w localStorage
    localStorage.setItem('language', lang);
    
    // Aktualizuj aktywny przycisk języka
    document.querySelectorAll('.language-btn').forEach(btn => {
        btn.classList.toggle('active', btn.getAttribute('data-lang') === lang);
    });
    
    // Tłumaczenie elementów z atrybutem data-translate
    document.querySelectorAll('[data-translate]').forEach(element => {
        const key = element.getAttribute('data-translate');
        if (translations[key] && translations[key][lang]) {
            element.textContent = translations[key][lang];
        }
    });
    
    // Tłumaczenie elementów bez atrybutu data-translate (na podstawie zawartości tekstowej)
    translateElementsByContent(document.body, lang);
    
    // Tłumaczenie atrybutów
    translateAttributes(lang);
}

// Funkcja do tłumaczenia elementów na podstawie zawartości tekstowej
function translateElementsByContent(element, lang) {
    // Pomijamy elementy script i style
    if (element.tagName === 'SCRIPT' || element.tagName === 'STYLE') {
        return;
    }
    
    // Sprawdzamy, czy element ma dzieci
    if (element.childNodes.length > 0) {
        // Iterujemy przez wszystkie dzieci elementu
        Array.from(element.childNodes).forEach(child => {
            // Jeśli dziecko jest tekstem
            if (child.nodeType === Node.TEXT_NODE && child.textContent.trim()) {
                const text = child.textContent.trim();
                if (text.length > 2) { // Pomijamy bardzo krótkie teksty
                    // Szukamy tłumaczenia dla tekstu
                    for (const key in translations) {
                        if (translations[key]['pl'] === text && translations[key][lang]) {
                            child.textContent = child.textContent.replace(text, translations[key][lang]);
                            break;
                        }
                    }
                }
            } else if (child.nodeType === Node.ELEMENT_NODE) {
                // Jeśli element ma już atrybut data-translate, pomijamy go
                // ponieważ zostanie przetłumaczony przez główną funkcję translatePage
                if (!child.hasAttribute('data-translate')) {
                    // Rekurencyjnie tłumaczymy zawartość elementu
                    translateElementsByContent(child, lang);
                }
            }
        });
    }
}

// Funkcja do tłumaczenia atrybutów
function translateAttributes(lang) {
    // Tłumaczenie placeholderów
    document.querySelectorAll('input[placeholder], textarea[placeholder]').forEach(element => {
        const placeholder = element.getAttribute('placeholder');
        if (placeholder) {
            for (const key in translations) {
                if (translations[key]['pl'] === placeholder && translations[key][lang]) {
                    element.setAttribute('placeholder', translations[key][lang]);
                    break;
                }
            }
        }
    });
    
    // Tłumaczenie atrybutów alt
    document.querySelectorAll('img[alt]').forEach(element => {
        const alt = element.getAttribute('alt');
        if (alt) {
            for (const key in translations) {
                if (translations[key]['pl'] === alt && translations[key][lang]) {
                    element.setAttribute('alt', translations[key][lang]);
                    break;
                }
            }
        }
    });
    
    // Tłumaczenie atrybutów title
    document.querySelectorAll('[title]').forEach(element => {
        const title = element.getAttribute('title');
        if (title) {
            for (const key in translations) {
                if (translations[key]['pl'] === title && translations[key][lang]) {
                    element.setAttribute('title', translations[key][lang]);
                    break;
                }
            }
        }
    });
    
    // Tłumaczenie atrybutów aria-label
    document.querySelectorAll('[aria-label]').forEach(element => {
        const ariaLabel = element.getAttribute('aria-label');
        if (ariaLabel) {
            for (const key in translations) {
                if (translations[key]['pl'] === ariaLabel && translations[key][lang]) {
                    element.setAttribute('aria-label', translations[key][lang]);
                    break;
                }
            }
        }
    });
}

// Funkcja do inicjalizacji systemu tłumaczeń
function initTranslations() {
    // Pobierz zapisany język z localStorage lub ustaw domyślny
    const savedLanguage = localStorage.getItem('language') || 'pl';
    
    // Dodaj event listenery do przycisków zmiany języka
    document.querySelectorAll('.language-btn').forEach(button => {
        button.addEventListener('click', function() {
            const lang = this.getAttribute('data-lang');
            translatePage(lang);
        });
    });
    
    // Ustaw początkowy język
    translatePage(savedLanguage);
}

// Inicjalizacja systemu tłumaczeń po załadowaniu strony
document.addEventListener('DOMContentLoaded', initTranslations);

// Dodaj tę funkcję na końcu pliku
function debugTranslations() {
    console.log("Debugowanie tłumaczeń:");
    
    // Wypisz wszystkie elementy z atrybutem data-translate
    const elementsWithDataTranslate = document.querySelectorAll('[data-translate]');
    console.log(`Elementy z atrybutem data-translate: ${elementsWithDataTranslate.length}`);
    
    // Wypisz wszystkie teksty na stronie
    const textNodes = [];
    function collectTextNodes(element) {
        if (element.nodeType === Node.TEXT_NODE && element.textContent.trim().length > 2) {
            textNodes.push(element.textContent.trim());
        } else if (element.nodeType === Node.ELEMENT_NODE) {
            if (element.tagName !== 'SCRIPT' && element.tagName !== 'STYLE') {
                Array.from(element.childNodes).forEach(collectTextNodes);
            }
        }
    }
    
    collectTextNodes(document.body);
    console.log(`Znaleziono ${textNodes.length} węzłów tekstowych na stronie`);
    
    // Sprawdź, ile tekstów ma tłumaczenia
    let textsWithTranslations = 0;
    textNodes.forEach(text => {
        for (const key in translations) {
            if (translations[key]['pl'] === text) {
                textsWithTranslations++;
                break;
            }
        }
    });
    
    console.log(`Teksty z tłumaczeniami: ${textsWithTranslations} z ${textNodes.length}`);
}

// Dodaj wywołanie funkcji debugującej po załadowaniu strony
document.addEventListener('DOMContentLoaded', function() {
    initTranslations();
    
    // Odkomentuj poniższą linię, aby włączyć debugowanie
    debugTranslations();
});